mapper.insert:
INSERT INTO sys_comment (
    user_id, experiment_id, root_id, parent_id, reply_to_user_id,
    content, like_count, status, reject_reason, reviewed_by, reviewed_time
) VALUES (
    #{userId}, #{experimentId}, #{rootId}, #{parentId}, #{replyToUserId},
    #{content}, #{likeCount}, #{status}, #{rejectReason}, #{reviewedBy}, #{reviewedTime}
)

mapper.select:
SELECT , FALSE AS liked_by_current_user, FALSE AS owned_by_current_user
WHERE c.status = 'APPROVED'
AND c.experiment_id = #{experimentId}
ORDER BY c.create_time DESC
LIMIT #{limit}

SELECT ,
       CASE WHEN cl.user_id IS NULL THEN FALSE ELSE TRUE END AS liked_by_current_user,
       CASE WHEN c.user_id = #{currentUserId} THEN TRUE ELSE FALSE END AS owned_by_current_user

LEFT JOIN sys_comment_like cl
       ON cl.comment_id = c.id AND cl.user_id = #{currentUserId}
WHERE c.status = 'APPROVED'
   OR c.user_id = #{currentUserId}

    AND c.experiment_id = #{experimentId}

ORDER BY c.create_time DESC

SELECT , FALSE AS liked_by_current_user, FALSE AS owned_by_current_user
c.status = 'PENDING'
AND c.content LIKE CONCAT('%', #{keyword}, '%')
AND c.experiment_id = #{experimentId}
ORDER BY c.create_time DESC LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE sys_comment
SET like_count = CASE
    WHEN like_count + #{delta} < 0 THEN 0
    ELSE like_count + #{delta}
END
WHERE id = #{id}
